1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { customer: { yearsInsured: number; previousContracts: number }; items: Array<{ type: string; cursed?: boolean; enchantment?: number }> }): { premium: number } {
16	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
17	
18	  const componentCounts: Record<string, number> = {};
19	  let base = 0;
20	  let itemSubtotal = 0;
21	  for (const item of input.items) {
22	    if (COMPONENT_TYPES.has(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
24	    } else {
25	      const itemBase = BASE_PREMIUMS[item.type];
26	      base += itemBase;
27	      itemSubtotal += itemBase + (item.cursed ? 0.5 * itemBase : 0) + ((item.enchantment ?? 0) >= 5 ? 0.3 * itemBase : 0);
28	    }
29	  }
30	  for (const [type, count] of Object.entries(componentCounts)) {
31	    const componentBase = count === 3 ? 60 : count * BASE_PREMIUMS[type];
32	    base += componentBase;
33	    itemSubtotal += componentBase;
34	  }
35	
36	  const loyalty = input.customer.yearsInsured >= 2 ? -0.2 * base : 0;
37	  const followUp = input.customer.previousContracts >= 1 ? -0.15 * base : 0;
38	  return { premium: Math.ceil(itemSubtotal + base * FIRST_INSURANCE_RATE + loyalty + followUp + PROCESSING_FEE) };
39	}
40	
41	export function claim(input: { items: Array<{ type: string; material?: string; enchantment?: number }>; damages: Array<{ itemType: string; amount: number }> }): { payout: number } {
42	  let payout = 0;
43	  for (const damage of input.damages) {
44	    const item = input.items.find((i) => i.type === damage.itemType);
45	    let amount = damage.amount;
46	    if (item && (item.enchantment ?? 0) >= 8) amount = amount * 0.5;
47	    payout += Math.max(0, amount - 100);
48	  }
49	  return { payout: Math.floor(payout) };
50	}
